var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제 7방위선, 거점 기지","JPN":"人類統合防衛軍第7防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 7th Defense Line","TWN":"人類共同保衛軍第七防線基地","THA":"ฐานทัพ แนวป้องกันที่ 7 กองกำลังป้องกันมนุษยชาติ","VTN":"Căn Cứ, Phòng Tuyến thứ 7 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất","SCN":"人类综合防卫军第7防线，据点基地","DEU":"Basis, 7. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit","FRA":"Base de la 7e ligne de défense des Forces de défense unies de l'humanité"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 뒤로 벌써 보름이나 지났는데, 본부에선 뭔가 알아낸 게 있나요?","JPN":"あれからもう半月経ちますが、本部の方では何か進展があったんでしょうか？","ENG":"It's been 2 weeks already. Has HQ found out anything yet?","TWN":"都已經過去半個月了，總部那邊都沒有什麼發現嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 예상대로 우리 세계의 기술력으로는 프로텍트를 해제할 수 없는 모양이에요.","JPN":"いいえ。予想通り、私たちの世界の技術力ではプロテクトを解除することはできないようです。","ENG":"No. As we expected, it is impossible to disable the protection with our technology.","TWN":"沒有，不出所料，以我們世界的技術還無法解除那些裝備上的防護器。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무기를 함선 밖으로 반출하면 즉시 분자단위로 분해되어 쓸 수 없다는 보고를 받았거든요.","JPN":"武器を艦船の外に搬出すると、すぐに分子単位に分解され、使えなくなるという報告を受けました。","ENG":"According to reports, the weapons disintegrate into atoms the moment they are taken outside of the ship.","TWN":"而且我收到的報告說，若是將武器搬離艦船之外，會立刻分解成分子，無法使用。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 역시 일이 그렇게 잘 풀릴 리 없겠죠.","JPN":"はぁ、やっぱりそう簡単にはいきませんよね。","ENG":"*Sigh...* I knew things weren't going to go so smoothly.","TWN":"哈啊，果然事情不會那麼順利。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 결국 방법은 그 안토노프라는 분이 기억을 되찾는 수밖에 없겠네요.","JPN":"じゃあ結局、あのアントノフという人が記憶を取り戻すしか方法はないんですね。","ENG":"The only thing left is for Antonov to get her memories back.","TWN":"那麼，只剩下讓那位名叫安東諾夫的人，找回記憶這一個辦法了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇겠죠.","JPN":"そうですね。","ENG":"I suppose so.","TWN":"沒錯。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"따라서 당분간 제가 이곳 제7 방위선의 담당관이 되어, 그자를 내사하기로 결정했습니다.","JPN":"というわけで、当分は私がこの第7防衛線の担当官となり、彼女を内偵することにしました。","ENG":"So for the time being, I've decided to be in charge of the 7th Defense Line and investigate her myself.","TWN":"所以我會臨時擔任第七防線的負責人，並且親自對她展開調查。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"내사라고요? 사령 본부로 이송하지 않고?","JPN":"内偵？　指令本部に移送するんじゃなくて？","ENG":"Investigate her yourself? Why not hand her over to HQ?","TWN":"親自調查？不把她移交給司令總部嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우린 아직 그자가 어떤 의도로 우리 세계로 왔는지 모릅니다. 기억을 잃었다는 것 자체가 우리를 기만하는 걸지도 모르죠.","JPN":"私たちはまだ彼女がなぜ私たちの世界に来たのかわかっていません。記憶喪失もただの嘘なのかもしれませんし。","ENG":"We have no idea what her intentions are for coming to this world. Plus, her amnesia could just be a ploy to make us lower our guards.","TWN":"我們目前還不清楚，她是帶著什麼目的來到我們世界的。也許失憶這件事，本身就是個謊言。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무엇보다도 그자에 관해서는 로스트 쉽이나 무기고 외에도 수상한 점이 많아요.","JPN":"なにより彼女に関しては、ロストシップや武器庫以外の点でも怪しいところが多いんです。","ENG":"But above all, there are many suspicious things about her other than the Lost Ship and the weapons.","TWN":"最重要的是，除了與她相關的失落艦船和那些武器外，還有許多其他可疑的部分。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 외에 수상한 점?","JPN":"それ以外の怪しいところ？","ENG":"What are they?","TWN":"其他可疑的地方？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아시다시피 이면 세계든, 현실 세계든 각 세계 간에는 <color=#ffd34c>양자 위상의 차이</color>가 존재해요.","JPN":"ご存知のとおり、裏世界であれ現実世界であれ、世界と世界の間には<color=#ffd34c>量子位相のズレ</color>が存在します。","ENG":"As you know, there's a <color=#ffd34c>quantum phase difference</color> between worlds and even between Counterside and ours.","TWN":"你也知道不管是異界還是現實世界，每個世界之間都存在<color=#ffd34c>量子能量差</color>。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 법칙을 무시하면 얼마 안 가 물질의 구성 원소가 유지력을 잃고 완전히 분해되어버리죠.","JPN":"この法則を無視すると、物質はやがて構成元素の維持力を失い、完全に分解されてしまいます。","ENG":"Ignoring this law will make any material lose its molecular structure and disintegrate.","TWN":"如果無視這個規律，物質的構成元素很快就會失去穩定性，並完全分解掉。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 그 엑자일러는 어떻죠? ","JPN":"しかしあのエグザイラーはどうでしょうか？ ","ENG":"But, what about the Exile?","TWN":"但那個流浪者呢？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"벌써 보름이나 지났는데 사라지지 않았잖아요.","JPN":"半月も経つのに、まだ消えていません。","ENG":"It's been over 2 weeks and she's still here.","TWN":"已經過去半個月了，她卻沒有消失。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};